        '  if(data.type==="OFFLINE_PREPARE_STATUS"){if(data.running){writeOfflinePrepState({running:true,status:"running",updatedAt:new Date().toISOString()})}else if(data.progress){writeOfflinePrepState({running:false,status:"partial",total:Number(data.progress.total||0),loaded:Number(data.progress.loaded||0),failed:Number(data.progress.failed||0),bytes:Number(data.progress.bytes||0),percent:Number(data.progress.percent||0),updatedAt:data.progress.updatedAt||new Date().toISOString()})}else if(data.meta&&data.meta.ok){writeOfflinePrepState({running:false,status:data.meta.partial?"partial":"done",total:Number(data.meta.total||0),loaded:Number(data.meta.loaded||0),failed:Number(data.meta.failed||0),bytes:Number(data.meta.bytes||0),percent:100,updatedAt:data.meta.completedAt||new Date().toISOString()})}updateOfflineBox();return}\n  if(data.type==="OFFLINE_PREPARE_DONE"){const ok=!!data.ok;const partial=!!data.partial;const finalStatus=ok?(partial?"partial":"done"):"partial";writeOfflinePrepState({running:false,status:finalStatus,total:Number(data.total||0),loaded:Number(data.loaded||0),failed:Number(data.failed||0),bytes:Number(data.bytes||0),percent:ok?100:Number(data.percent||readOfflinePrepState().percent||0),updatedAt:new Date().toISOString()});setJson(OFFLINE_SYNC_META_KEY,{appVersion:typeof APP_BUILD_ID==="string"?APP_BUILD_ID:"",contentVersion:String(window.__darRemoteBuildId||""),databaseSchemaVersion:OFFLINE_DB_VERSION,lastSuccessfulSync:ok?new Date().toISOString():(getJson(OFFLINE_SYNC_META_KEY,{lastSuccessfulSync:""}).lastSuccessfulSync||""),syncStatus:ok?(partial?"partial":"done"):"partial",pendingLocalChanges:getJson("darOfflineQueueCountV1",0),acknowledgedUpdateVersion:String(window.__darRemoteBuildId||"")});offlineDbSet("meta","syncStatus",{state:finalStatus,payload:data,at:new Date().toISOString()});const hint=$("offlinePrepHint");if(hint)hint.textContent=partial?`Offline-Paket fast fertig (${data.failed||0} Dateien fehlgeschlagen). Download kann fortgesetzt werden.`:ok?"Offline-Nutzung vollständig eingerichtet":"Offline-Download kann fortgesetzt werden.";updateOfflineBox();return}',
