for path in FILES:
    text = path.read_text(encoding="utf-8")
    if CSS_ADD not in text:
        text = text.replace(
            ".offline-prep-progress span,.offline-prep-progress small{font-size:12px;color:var(--muted)}",
            ".offline-prep-progress span,.offline-prep-progress small{font-size:12px;color:var(--muted)}\n" + CSS_ADD,
            1,
        )
    for old, new in REPLACEMENTS:
        if old not in text:
            raise SystemExit(f"Missing pattern in {path}: {old[:80]}...")
        text = text.replace(old, new, 1)
    path.write_text(text, encoding="utf-8")
    print("Patched", path)
